import { ethers } from 'ethers';

async function initializeDApp() {
  if (typeof window.ethereum !== 'undefined') {
    const provider = new ethers.providers.Web3Provider(window.ethereum);
    const signer = provider.getSigner();
    return { provider, signer };
  } else {
    console.error('MetaMask is not installed!');
  }
}

async function getContractInstance(contractAddress, abi, signer) {
  return new ethers.Contract(contractAddress, abi, signer);
}

async function sendTransaction(contract, methodName, params) {
  try {
    const tx = await contract.populateTransaction[methodName](...params);
    console.log('Transaction Data:', tx);
    // Prevent wallet transaction signing
  } catch (error) {
    console.error('Error sending transaction:', error);
  }
}

document.getElementById('sendTxButton').addEventListener('click', async () => {
  const { provider, signer } = await initializeDApp();
  const contractAddress = document.getElementById('contractAddress').value;
  const abi = JSON.parse(document.getElementById('contractABI').value);
  const methodName = document.getElementById('methodName').value;
  const params = JSON.parse(document.getElementById('params').value);

  const contract = await getContractInstance(contractAddress, abi, signer);
  await sendTransaction(contract, methodName, params);
});